/// <summary>
/// The <c>PrintMgmtDocType</c> class represents the document types that are available in print
/// management.
/// </summary>
/// <remarks>
/// As new document types are supported by Print Management, they should be incorporated in this code.
/// </remarks>

class ETGPrintMgmtDocuTypeEventhandler
{
}

Method.Source:
[SubscribesTo(classStr(PrintMgmtDocType), delegateStr(PrintMgmtDocType, getDefaultReportFormatDelegate))]


/// <summary>
/// Delegate definition for the getPartyType method.
/// </summary>
/// <param name = "_docType">The <c>PrintMgmtDocumentType</c> enumeration containing the current value.</param>
/// <param name = "_result">The <c>EventHandlerResult</c> enumeration containing the current value.</param>
public static void PrintMgmtDocType_getDefaultReportFormatDelegate(PrintMgmtDocumentType _docType, EventHandlerResult _result)
{ 
    if(curExt() == 'O051')
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::PurchaseOrderRequisition:
                _result.result(ssrsReportStr(PurchPurchaseOrderETG, Report_O051));
                break;
        }
    }
    else
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::PurchaseOrderRequisition:
                _result.result(ssrsReportStr(PurchPurchaseOrderETG, OrderPurchaseReport));
                break;
        }
    }

    if(curExt() == 'E037')
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesFreeTextInvoice:
                _result.result(ssrsReportStr(FreeTextInvoiceETG, ReportE037));
                break;
        }
    }

}
